const url = $input.item.json.url;
let html = '';
try {
  html = await this.helpers.httpRequest({ method: 'GET', url, timeout: 60000 });
} catch(e) {
  html = 'ERROR: ' + e.message;
}
return { json: { ...$input.item.json, data: typeof html === 'string' ? html : JSON.stringify(html) } };

const c = $input.first().json.confidence;
let severity = 2;
if (c === 'medium') severity = 3;
if (c === 'high') severity = 4;
return [{json: {...$input.first().json, severity}}];

const html = ($input.item.json.data || '').substring(0, 8000);
const prompt = 'You are extracting ICP-relevant text from a public web page.\n\nTask:\n1) Remove navigation, footer, cookie banners, repeated UI labels.\n2) Keep only ICP-relevant sections for the given page type.\n3) Return STRICT JSON with keys: normalized_text (string).\n\nPage type: ' + $input.item.json.page_type + '\nURL: ' + $input.item.json.url + '\n\nHTML (first 8000 chars):\n' + html;

const data = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.anthropic.com/v1/messages',
  headers: { "x-api-key": "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", "anthropic-version": "2023-06-01", "content-type": "application/json" },
  body: JSON.stringify({ model: 'claude-sonnet-4-20250514', max_tokens: 4096, messages: [{ role: 'user', content: prompt }] })
});
const text = data.content[0].text;
let parsed;
try { parsed = JSON.parse(text); } catch(e) {
  const m = text.match(/\{[\s\S]*\}/);
  parsed = m ? JSON.parse(m[0]) : { normalized_text: text };
}
return { json: { ...$input.item.json, ...parsed, text: parsed.normalized_text } };

const normData = $('Normalize Content (LLM)').item.json;
const content = normData.text || normData.normalized_text || '';
const prompt = 'You are an ICP analyst. Given normalized page content and its surface type, extract ICP indicators.\n\nReturn STRICT JSON with keys:\n- segment_signals: array of strings\n- buyer_signals: array of strings\n- vertical_signals: array of strings\n- inferred_segment: one of SMB, Mid-market, Enterprise or null\n- inferred_buyer: one of operator, manager, executive or null\n- inferred_buyer_type: one of technical, economic or null\n- inferred_verticality: one of horizontal, vertical or null\n\nSurface: ' + normData.page_type + '\nCompany: ' + normData.company_name + '\n\nContent:\n' + content;

const data = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.anthropic.com/v1/messages',
  headers: { "x-api-key": "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", "anthropic-version": "2023-06-01", "content-type": "application/json" },
  body: JSON.stringify({ model: 'claude-sonnet-4-20250514', max_tokens: 4096, messages: [{ role: 'user', content: prompt }] })
});
const text = data.content[0].text;
let parsed;
try { parsed = JSON.parse(text); } catch(e) {
  const m = text.match(/\{[\s\S]*\}/);
  parsed = m ? JSON.parse(m[0]) : {};
}
// Merge all upstream data
return { json: { ...normData, ...$input.item.json, ...parsed, indicators: parsed } };

const extractData = $('Extract ICP Indicators (LLM)').item.json;
const prevData = $('Load Previous Snapshot').item.json;
const current = JSON.stringify(extractData.indicators || extractData);
const previous = JSON.stringify(prevData || {});
const prompt = 'You are an ICP drift detector. Compare current vs previous ICP indicators.\n\nReturn STRICT JSON with keys:\n- has_drift: boolean\n- drift_direction: one of the fixed taxonomy or null\n- drift_summary: string or null\n- confidence_inputs: integer\n\nCurrent:\n' + current + '\n\nPrevious:\n' + previous;

const data = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.anthropic.com/v1/messages',
  headers: { "x-api-key": "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", "anthropic-version": "2023-06-01", "content-type": "application/json" },
  body: JSON.stringify({ model: 'claude-sonnet-4-20250514', max_tokens: 4096, messages: [{ role: 'user', content: prompt }] })
});
const text = data.content[0].text;
let parsed;
try { parsed = JSON.parse(text); } catch(e) {
  const m = text.match(/\{[\s\S]*\}/);
  parsed = m ? JSON.parse(m[0]) : { has_drift: false };
}
const normData = $('Normalize Content (LLM)').item.json;
return { json: { ...normData, ...extractData, ...parsed, prev_snapshot_id: prevData.prev_snapshot_id || null, snapshot_id: $('Upsert Snapshot').item.json.snapshot_id || '' } };
